#header {
  width: 100%;
  height: 80px;
  background-color: #333;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
}

.main-box {
  float: left;
  width: 70%;
  margin-right: 2%;
}

/* 默认电脑样式 */
.sidebar { width: 300px; float: left; }

/* 手机样式：当屏幕小于 768px 时 */
@media (max-width: 768px) {
  .sidebar {
    width: 100%; /* 侧边栏变全宽，自动排到主内容下方 */
    float: none;
    background-color: #f0f0f0;
  }
}

/* 默认基础样式：大屏端维持定宽和原始色彩 */
#myBox {
  width: 500px;
  height: 200px;
  background-color: red;
}

/* 媒体查询栏配置：设定最大视口约束阈值为 600px */
@media (max-width: 600px) {
  #myBox {
    width: 100%;
    background-color: green;
  }
}
